-- common shortcuts

--bindr = $mainMod, $mainMod_L, exec, pkill rofi || rofi -show drun -modi drun,filebrowser,run,window # Super Key to Launch rofi menu

hl.bind(mainMod .. " + " .. "D", hl.dsp.exec_cmd("pkill rofi || true && rofi -show drun -modi drun,filebrowser,run,window"))

-- Main Menu (APP Launcher)

hl.bind(mainMod .. " + " .. "B", hl.dsp.exec_cmd("xdg-open https://"))

-- default browser

hl.bind(mainMod .. " + " .. "A", hl.dsp.exec_cmd("pkill rofi || true && ags -t 'overview'"))

-- desktop overview (if installed)

hl.bind(mainMod .. " + " .. "Return", hl.dsp.exec_cmd("kitty"))

--terminal

hl.bind(mainMod .. " + " .. "E", hl.dsp.exec_cmd("thunar"))

--file manager

hl.bind(mainMod .. " + " .. "F1", hl.dsp.exec_cmd("thorium-browser"))

hl.bind(mainMod .. " + " .. "F2", hl.dsp.exec_cmd("warp-terminal"))

hl.bind(mainMod .. " + " .. "F3", hl.dsp.exec_cmd("ghostty"))

-- Back and Forth

hl.bind(mainMod .. " + " .. "TAB", hl.dsp.focus({ workspace = "previous" }))

