hl.bind(mainMod .. " + " .. "CTRL" .. " + " .. "R", hl.dsp.exec_cmd("local_var_HOME/.config/hypr/scripts/RofiThemeSelector.sh"))

-- KooL Rofi Menu Theme Selector

hl.bind(mainMod .. " + " .. "CTRL + SHIFT" .. " + " .. "R", hl.dsp.exec_cmd("pkill rofi || true && local_var_HOME/.config/hypr/scripts/RofiThemeSelector-modified.sh"))

-- modified Rofi Theme Selector

hl.bind(mainMod .. " + " .. "SHIFT" .. " + " .. "F", hl.dsp.window.fullscreen())

-- whole full screen

hl.bind(mainMod .. " + " .. "CTRL" .. " + " .. "F", hl.dsp.window.fullscreen())

-- fake full screen

hl.bind(mainMod .. " + " .. "SPACE", hl.dsp.window.float())

--Float Mode

hl.bind(mainMod .. " + " .. "ALT" .. " + " .. "SPACE", hl.dsp.exec_cmd("hyprctl dispatch workspaceopt allfloat"))

--All Float Mode

hl.bind(mainMod .. " + " .. "SHIFT" .. " + " .. "Return", hl.dsp.exec_cmd("[float; move 15% 5%; size 70% 60%] kitty"))

-- Dropdown terminal

-- Desktop zooming or magnifier

hl.bind(mainMod .. " + " .. "ALT" .. " + " .. "mouse_down", hl.dsp.exec_cmd("hyprctl keyword cursor:zoom_factor $(hyprctl getoption cursor:zoom_factor | awk 'NR==1 {factor = local_var_2; if (factor < 1) {factor = 1}; print factor * 2.0}')"))

hl.bind(mainMod .. " + " .. "ALT" .. " + " .. "mouse_up", hl.dsp.exec_cmd("hyprctl keyword cursor:zoom_factor $(hyprctl getoption cursor:zoom_factor | awk 'NR==1 {factor = local_var_2; if (factor < 1) {factor = 1}; print factor / 2.0}')"))

